1	// claim-office.ts
2	
3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	function groupByType(items: Item[]): Map<string, Item[]> {
31	  const groups = new Map<string, Item[]>();
32	  for (const item of items) {
33	    const group = groups.get(item.type) ?? [];
34	    group.push(item);
35	    groups.set(item.type, group);
36	  }
37	  return groups;
38	}
39	
40	function premiumForGroup(type: string, group: Item[]): number {
41	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
42	    return COMPONENT_BLOCK_PREMIUM;
43	  }
44	  return group.length * BASE_PREMIUM_BY_TYPE[type];
45	}
46	
47	function itemPremium(item: Item): number {
48	  let premium = BASE_PREMIUM_BY_TYPE[item.type];
49	  if (item.cursed) {
50	    premium += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
51	  }
52	  if (item.enchantment !== undefined && item.enchantment >= 5) {
53	    premium += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
54	  }
55	  return premium;
56	}
57	
58	function hasCursedItem(items: Item[]): boolean {
59	  return items.some((item) => item.cursed);
60	}
61	
62	function hasHighEnchantmentItem(items: Item[]): boolean {
63	  return items.some((item) => item.enchantment !== undefined && item.enchantment >= 5);
64	}
65	
66	function hasItemModifier(items: Item[]): boolean {
67	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
68	}
69	
70	function baseTotalForItems(items: Item[]): number {
71	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
72	}
73	
74	function premiumForItems(items: Item[]): number {
75	  if (hasItemModifier(items)) {
76	    let total = 0;
77	    for (const item of items) {
78	      total += itemPremium(item);
79	    }
80	    return total;
81	  }
82	  let total = 0;
83	  for (const [type, group] of groupByType(items)) {
84	    total += premiumForGroup(type, group);
85	  }
86	  return total;
87	}
88	
89	function isFirstContract(input: QuoteInput): boolean {
90	  return input.customerYears === 0 && input.previousContracts === 0;
91	}
92	
93	export function quote(input: QuoteInput): number {
94	  let premium = premiumForItems(input.items);
95	  if (hasItemModifier(input.items) && isFirstContract(input)) {
96	    premium += baseTotalForItems(input.items) * 0.1;
97	  }
98	  return premium + PROCESSING_FEE;
99	}
