162	
163	  // --- Claim: enchantment threshold ---
164	  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
165	
166	  // --- Claim: dragon material ---
167	  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");
168	
169	  // --- Claim: enchantment vs dragon material (50% rule wins) ---
170	  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
171	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
172	
173	  // --- Claim: payout rounding ---
174	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
175	
176	  // --- Multiple items of the same type ---
177	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
178	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
179	
180	  // --- Cap ---
181	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
182	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
183	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
184	
185	  // --- Cap exhaustion across successive claims ---
186	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
187	  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");
188	
189	  // --- Error cases ---
190	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
191	  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
192	  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
193	  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
194	});
